import{_ as t,c as e,o as a,a4 as o}from"./chunks/framework.HaEZziQ1.js";const l="/FrontEndLearnNotes/assets/三次握手.DUJXojUl.png",b=JSON.parse('{"title":"网络协议(TCP HTTP)面试题","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端面试相关/计算机基础面试题/网络协议面试题.md","filePath":"Document/前端面试相关/计算机基础面试题/网络协议面试题.md","lastUpdated":1709668918000}'),i={name:"Document/前端面试相关/计算机基础面试题/网络协议面试题.md"},r=o('<h1 id="网络协议-tcp-http-面试题" tabindex="-1">网络协议(TCP HTTP)面试题 <a class="header-anchor" href="#网络协议-tcp-http-面试题" aria-label="Permalink to &quot;网络协议(TCP HTTP)面试题&quot;">​</a></h1><p>计算机网络基础面试题</p><p>参考：<a href="https://baijiahao.baidu.com/s?id=1744563217713889117&amp;wfr=spider&amp;for=pc" target="_blank" rel="noreferrer">https://baijiahao.baidu.com/s?id=1744563217713889117&amp;wfr=spider&amp;for=pc</a></p><p>《网络协议》学习文档笔记：</p><ul><li><a href="http://www.zhufengpeixun.com/strong/html/12.Network-1.html" target="_blank" rel="noreferrer">12.Network-1</a></li><li><a href="http://www.zhufengpeixun.com/strong/html/12-Network-2.html" target="_blank" rel="noreferrer">12-Network-2</a></li><li><a href="http://www.zhufengpeixun.com/strong/html/12.NetWork-3.html" target="_blank" rel="noreferrer">12.NetWork-3</a></li><li><a href="http://www.zhufengpeixun.com/strong/html/13.tcp.html" target="_blank" rel="noreferrer">13.tcp</a></li><li><a href="http://www.zhufengpeixun.com/strong/html/14.http-1.html" target="_blank" rel="noreferrer">14.http-1</a></li><li><a href="http://www.zhufengpeixun.com/strong/html/14.http-2.html" target="_blank" rel="noreferrer">14.http-2</a></li></ul><h2 id="http-协议" tabindex="-1">HTTP 协议 <a class="header-anchor" href="#http-协议" aria-label="Permalink to &quot;HTTP 协议&quot;">​</a></h2><h3 id="http-协议的主要特点" tabindex="-1">HTTP 协议的主要特点 <a class="header-anchor" href="#http-协议的主要特点" aria-label="Permalink to &quot;HTTP 协议的主要特点&quot;">​</a></h3><ul><li>简单快速 <ul><li>每个资源和图片的地址都是固定的</li></ul></li><li>灵活</li><li>无连接</li><li>无状态：不会保存状态</li></ul><h3 id="http-报文的组成部分" tabindex="-1">HTTP 报文的组成部分 <a class="header-anchor" href="#http-报文的组成部分" aria-label="Permalink to &quot;HTTP 报文的组成部分&quot;">​</a></h3><h4 id="请求报文" tabindex="-1">请求报文 <a class="header-anchor" href="#请求报文" aria-label="Permalink to &quot;请求报文&quot;">​</a></h4><ul><li>请求行</li><li>请求头</li><li>空行</li><li>请求体</li></ul><h4 id="响应报文" tabindex="-1">响应报文 <a class="header-anchor" href="#响应报文" aria-label="Permalink to &quot;响应报文&quot;">​</a></h4><ul><li>状态行</li><li>响应头</li><li>空行</li><li>响应体</li></ul><h3 id="http-方法" tabindex="-1">HTTP 方法 <a class="header-anchor" href="#http-方法" aria-label="Permalink to &quot;HTTP 方法&quot;">​</a></h3><p>GET 获取资源</p><p>POST 传输资源</p><p>PUT 更新资源</p><p>DELETE 删除资源</p><p>HEAD 获得报文首部</p><h3 id="post-和-get-的区别" tabindex="-1">POST 和 GET 的区别 <a class="header-anchor" href="#post-和-get-的区别" aria-label="Permalink to &quot;POST 和 GET 的区别&quot;">​</a></h3><ul><li>GET 在浏览器回退时是无害的，而 POST 会再次提交请求</li><li>GET 产生的 URL 地址可以被收藏，而 POST 不可以</li><li>GET 请求会被浏览器主动缓存，而 POST 不会，除非手动设置</li><li>GET 请求只能进行 url 编码，而 POST 支持多种编码方式</li><li>GET 请求参数会被完整保留在浏览器历史记录里，而 POST 中的参数不会被保留</li><li>GET 请求在 URL 中传送的参数是有长度限制的，而 POST 没有限制</li><li>对参数的数据类型，GET 只接受 ASCII 字符，而 POST 没有限制</li><li>GET 比 POST 更不安全，因为GET 参数直接暴露在 URL 上，且会被浏览器保存历史纪录，所以不能用来传递敏感信息；Post 不会，但是在抓包的情况下两者都是⼀样的。</li><li>GET 参数通过 URL 传递，POST 放在 Request body 中</li><li>Post 可以通过 request body 来传输⽐ Get 更多的数据， Get 没有这个技术</li><li>URL 有⻓度限制，会影响 Get 请求，但是这个⻓度限制是浏览器规定的，不是 RFC 规定的</li><li>Post ⽀持更多的编码类型且不对数据类型限制</li></ul><h3 id="http-状态码" tabindex="-1">HTTP 状态码 <a class="header-anchor" href="#http-状态码" aria-label="Permalink to &quot;HTTP 状态码&quot;">​</a></h3><p>200OK：客户端请求成功</p><p>206 Partial Content：客户发送了一个带有 Range 头的 GET 请求，服务器完成了它</p><p>301 Moved Permanently：所请求的页面已经转移至新的 url</p><p>302 Found：所请求的页面已经临时转移至新的 url</p><p>304 Not Modified：客户端有缓冲的文档并发出了一个条件性的请求，服务器告诉客户原来缓冲的文档还可以继续使用</p><p>400 Bad Request：客户端请求有语法错误，不能被服务器所理解</p><p>401 Unauthorized：请求未经授权，这个状态代码必须和 WWW-Authenticate 报头域一起使用</p><p>403 Forbidden：对被请求页面的访问被禁止</p><p>404 Not Found：请求资源不存在</p><p>500 Internal Server Error：服务器发生不可预期的错误原来缓冲的文档还可以继续使用</p><p>503 Server Unavailable：请求未完成，服务器临时过载或当机，一段时间后可能恢复正常</p><p>100 Continue 继续。客户端应继续其请求 101 Switching Protocols 切换协议。服务器根据客户端的请求切换协议。只能切换到更高级的协议，例如，切换到 HTTP 的新版本协议 200 OK 请求成功。一般用于 GET 与 POST 请求 201 Created 已创建。成功请求并创建了新的资源 202 Accepted 已接受。已经接受请求，但未处理完成 203 Non-Authoritative Information 非授权信息。请求成功。但返回的 meta 信息不在原始的服务器，而是一个副本 204 No Content 无内容。服务器成功处理，但未返回内容。在未更新网页的情况下，可确保浏览器继续显示当前文档 205 Reset Content 重置内容。服务器处理成功，用户终端（例如：浏览器）应重置文档视图。可通过此返回码清除浏览器的表单域 206 Partial Content 部分内容。服务器成功处理了部分 GET 请求 300 Multiple Choices 多种选择。请求的资源可包括多个位置，相应可返回一个资源特征与地址的列表用于用户终端（例如：浏览器）选择 301 Moved Permanently 永久移动。请求的资源已被永久的移动到新URI，返回信息会包括新的 URI，浏览器会自动定向到新 URI。今后任何新的请求都应使用新的 URI 代替 302 Found 临时移动。与 301 类似。但资源只是临时被移动。客户端应继续使用原有 URI 303 See Other 查看其它地址。与 301 类似。使用 GET 和 POST 请求查看 304 Not Modified 未修改。所请求的资源未修改，服务器返回此状态码时，不会返回任何资源。客户端通常会缓存访问过的资源，通过提供一个头信息指出客户端希望只返回在指定日期之后修改的资源 305 Use Proxy 使用代理。所请求的资源必须通过代理访问 306 Unused 已经被废弃的 HTTP 状态码 307 Temporary Redirect 临时重定向。与 302 类似。使用 GET 请求重定向 400 Bad Request 客户端请求的语法错误，服务器无法理解 401 Unauthorized 请求要求用户的身份认证 402 Payment Required 保留，将来使用 403 Forbidden 服务器理解请求客户端的请求，但是拒绝执行此请求 404 Not Found 服务器无法根据客户端的请求找到资源（网页）。通过此代码，网站设计人员可设置&quot;您所请求的资源无法找到&quot;的个性页面 405 Method Not Allowed 客户端请求中的方法被禁止 406 Not Acceptable 服务器无法根据客户端请求的内容特性完成请求 407 Proxy Authentication Required 请求要求代理的身份认证，与 401 类似，但请求者应当使用代理进行授权 408 Request Time-out 服务器等待客户端发送的请求时间过长，超时 409 Conflict 服务器完成客户端的 PUT 请求是可能返回此代码，服务器处理请求时发生了冲突 410 Gone 客户端请求的资源已经不存在。410 不同于 404，如果资源以前有现在被永久删除了可使用 410 代码，网站设计人员可通过 301 代码指定资源的新位置 411 Length Required 服务器无法处理客户端发送的不带 Content-Length 的请求信息 412 Precondition Failed 客户端请求信息的先决条件错误 413 Request Entity Too Large 由于请求的实体过大，服务器无法处理，因此拒绝请求。为防止客户端的连续请求，服务器可能会关闭连接。如果只是服务器暂时无法处理，则会包含一个 Retry-After 的响应信息 414 Request-URI Too Large 请求的 URI 过长（URI 通常为网址），服务器无法处理 415 Unsupported Media Type 服务器无法处理请求附带的媒体格式 416 Requested range not satisfiable 客户端请求的范围无效 417 Expectation Failed 服务器无法满足 Expect 的请求头信息 500 Internal Server Error 服务器内部错误，无法完成请求 501 Not Implemented 服务器不支持请求的功能，无法完成请求 502 Bad Gateway 作为网关或者代理工作的服务器尝试执行请求时，从远程服务器接收到了一个无效的响应 503 Service Unavailable 由于超载或系统维护，服务器暂时的无法处理客户端的请求。延时的长度可包含在服务器的 Retry-After 头信息中 504 Gateway Time-out 充当网关或代理的服务器，未及时从远端服务器获取请求 505 HTTP Version not supported 服务器不支持请求的 HTTP 协议的版本，无法完成处理</p><h3 id="http-状态码及其含义" tabindex="-1">HTTP 状态码及其含义 <a class="header-anchor" href="#http-状态码及其含义" aria-label="Permalink to &quot;HTTP 状态码及其含义&quot;">​</a></h3><h4 id="_1xx-信息状态码" tabindex="-1">1XX ：信息状态码 <a class="header-anchor" href="#_1xx-信息状态码" aria-label="Permalink to &quot;1XX ：信息状态码&quot;">​</a></h4><ul><li>100 Continue 继续，一般在发送 post 请求时，已发送了 http header 之后服务端</li><li>将返回此信息，表示确认，之后发送具体参数信息</li></ul><h4 id="_2xx-成功状态码" tabindex="-1">2XX ：成功状态码 <a class="header-anchor" href="#_2xx-成功状态码" aria-label="Permalink to &quot;2XX ：成功状态码&quot;">​</a></h4><ul><li>200 OK 正常返回信息</li><li>201 Created 请求成功并且服务器创建了新的资源</li><li>202 Accepted 服务器已接受请求，但尚未处理</li><li>204 No content ，表示请求成功，但响应报⽂不含实体的主体部分</li><li>205 Reset Content ，表示请求成功，但响应报⽂不含实体的主体部分，但是与 204响应不同在于要求请求⽅重置内容</li><li>206 Partial Content ，进⾏范围请求</li></ul><h4 id="_3xx-重定向" tabindex="-1">3XX ：重定向 <a class="header-anchor" href="#_3xx-重定向" aria-label="Permalink to &quot;3XX ：重定向&quot;">​</a></h4><ul><li>301 Moved Permanently 永久性重定向，表示资源已被分配了新的 URL。</li><li>302 Found 临时性重定向，表示资源临时被分配了新的 URL。</li><li>303 See Other 表示资源存在着另⼀个 URL，应使⽤ GET ⽅法获取资源。</li><li>304 Not Modified 表示服务器允许访问资源，但因发⽣请求未满⾜条件的情况。</li><li>307 temporary redirect ，临时重定向，和302含义类似，但是期望客户端保持请求⽅法不变向新的地址发出请求</li></ul><h4 id="_4xx-客户端错误" tabindex="-1">4XX ：客户端错误 <a class="header-anchor" href="#_4xx-客户端错误" aria-label="Permalink to &quot;4XX ：客户端错误&quot;">​</a></h4><ul><li>400 Bad Request 请求报⽂存在语法错误，服务器无法理解请求的格式，客户端不应当尝试再次使用相同的内容发起请求。</li><li>401 Unauthorized 请求未授权，表示发送的请求需要有通过 HTTP 认证的认证信息。</li><li>403 Forbidden 禁止访问，表示对请求资源的访问被服务器拒绝。</li><li>404 Not Found 找不到如何与 URI 相匹配的资源，表示在服务器上没有找到请求的资源。</li></ul><h4 id="_5xx-服务器错误" tabindex="-1">5XX: 服务器错误 <a class="header-anchor" href="#_5xx-服务器错误" aria-label="Permalink to &quot;5XX: 服务器错误&quot;">​</a></h4><ul><li>500 Internal Server Error 最常⻅的服务器端错误，表示服务器端在执⾏请求时发⽣了错误。</li><li>501 Not Implemented ，表示服务器不⽀持当前请求所需要的某个功能</li><li>503 Service Unavailable 服务器端暂时无法处理请求，表明服务器暂时处于超负载或正在停机维护，⽆法处理请求。</li></ul><h3 id="http-首部" tabindex="-1">HTTP 首部 <a class="header-anchor" href="#http-首部" aria-label="Permalink to &quot;HTTP 首部&quot;">​</a></h3><h4 id="通用首部" tabindex="-1">通用首部 <a class="header-anchor" href="#通用首部" aria-label="Permalink to &quot;通用首部&quot;">​</a></h4><table><thead><tr><th style="text-align:center;">通⽤字段</th><th style="text-align:center;">作⽤</th></tr></thead><tbody><tr><td style="text-align:center;">Cache-Control</td><td style="text-align:center;">控制缓存的⾏为</td></tr><tr><td style="text-align:center;">Connection</td><td style="text-align:center;">浏览器想要优先使⽤的连接类型，⽐如 keep-alive</td></tr><tr><td style="text-align:center;">Date</td><td style="text-align:center;">创建报⽂时间</td></tr><tr><td style="text-align:center;">Pragma</td><td style="text-align:center;">报⽂指令</td></tr><tr><td style="text-align:center;">Via</td><td style="text-align:center;">代理服务器相关信息</td></tr><tr><td style="text-align:center;">Transfer-Encoding</td><td style="text-align:center;">传输编码⽅式</td></tr><tr><td style="text-align:center;">Upgrade</td><td style="text-align:center;">要求客户端升级协议</td></tr><tr><td style="text-align:center;">Warning</td><td style="text-align:center;">一个一般性的警告，表示在内容中可能存在错误</td></tr></tbody></table><h4 id="请求首部" tabindex="-1">请求首部 <a class="header-anchor" href="#请求首部" aria-label="Permalink to &quot;请求首部&quot;">​</a></h4><table><thead><tr><th style="text-align:left;">请求字段</th><th>作用</th></tr></thead><tbody><tr><td style="text-align:left;">Accept</td><td>可接受的响应内容类型（Content-Types）。</td></tr><tr><td style="text-align:left;">Accept-Charset</td><td>可接受的字符集</td></tr><tr><td style="text-align:left;">Accept-Encoding</td><td>可接受的响应内容的编码方式。</td></tr><tr><td style="text-align:left;">Accept-Language</td><td>可接受的响应内容语言列表。</td></tr><tr><td style="text-align:left;">Accept-Datetime</td><td>可接受的按照时间来表示的响应内容版本</td></tr><tr><td style="text-align:left;">Expect</td><td>表示客户端要求服务器做出特定的行为</td></tr><tr><td style="text-align:left;">From</td><td>发起此请求的用户的邮件地址</td></tr><tr><td style="text-align:left;">Host</td><td>服务器的域名</td></tr><tr><td style="text-align:left;">If-Match</td><td>两端资源标记比较</td></tr><tr><td style="text-align:left;">If-Modified-Since</td><td>本地资源未修改返回 304（比较时间）</td></tr><tr><td style="text-align:left;">If-None-Match</td><td>本地资源未修改返回 304（比较标记）</td></tr><tr><td style="text-align:left;">User-Agent</td><td>客户端信息</td></tr><tr><td style="text-align:left;">Max-Forwards</td><td>限制可被代理及网关转发的次数</td></tr><tr><td style="text-align:left;">Proxy-Authorization</td><td>向代理服务器发送验证信息</td></tr><tr><td style="text-align:left;">Range</td><td>表示请求某个实体的一部分，字节偏移以 0 开始。</td></tr><tr><td style="text-align:left;">Referer</td><td>表示浏览器所访问的前一个页面</td></tr><tr><td style="text-align:left;">TE</td><td>传输编码方式</td></tr></tbody></table><h4 id="响应首部" tabindex="-1">响应首部 <a class="header-anchor" href="#响应首部" aria-label="Permalink to &quot;响应首部&quot;">​</a></h4><table><thead><tr><th>响应字段</th><th>作用</th></tr></thead><tbody><tr><td>Accept-Ranges</td><td>是否支持某些种类的范围</td></tr><tr><td>Age</td><td>资源在代理缓存中存在的时间</td></tr><tr><td>ETag</td><td>资源标识</td></tr><tr><td>Location</td><td>客户端重定向到某个 URL</td></tr><tr><td>Proxy-Authenticate</td><td>向代理服务器发送验证信息</td></tr><tr><td>Server</td><td>服务器名字</td></tr><tr><td>WWW-Authenticate</td><td>获取资源需要的验证信息</td></tr></tbody></table><h4 id="实体首部" tabindex="-1">实体首部 <a class="header-anchor" href="#实体首部" aria-label="Permalink to &quot;实体首部&quot;">​</a></h4><table><thead><tr><th>实体字段</th><th>作用</th></tr></thead><tbody><tr><td>Allow</td><td>资源的正确请求方式</td></tr><tr><td>Content-Encoding</td><td>内容的编码格式</td></tr><tr><td>Content-Language</td><td>内容使用的语言</td></tr><tr><td>Content-Length</td><td>request body 长度</td></tr><tr><td>Content-Location</td><td>返回数据的备用地址</td></tr><tr><td>Content-MD5</td><td>Base64 加密格式的内容 MD5 检验值</td></tr><tr><td>Content-Range</td><td>内容的位置范围</td></tr><tr><td>Content-Type</td><td>请求体的 MIME 类型 （用于 POST 和 PUT 请求中）</td></tr><tr><td>Expires</td><td>内容的过期时间</td></tr><tr><td>Last_modified</td><td>内容的最后修改时间</td></tr></tbody></table><h3 id="说下常见的-http-的头部" tabindex="-1">说下常见的 HTTP 的头部 <a class="header-anchor" href="#说下常见的-http-的头部" aria-label="Permalink to &quot;说下常见的 HTTP 的头部&quot;">​</a></h3><p>参考回答：</p><p>可以将 http 首部分为通用首部，请求首部，响应首部，实体首部</p><p>通用首部表示一些通用信息，比如 date 表示报文创建时间，</p><p>请求首部就是请求报文中独有的，如 cookie，和缓存相关的如 if-Modified-Since</p><p>响应首部就是响应报文中独有的，如 set-cookie，和重定向相关的 location， 实体首部用来描述实体部分，如 allow 用来描述可执行的请求方法，content-type 描述主题类型，content-Encoding 描述主体的编码方式。</p><h3 id="dns" tabindex="-1">DNS <a class="header-anchor" href="#dns" aria-label="Permalink to &quot;DNS&quot;">​</a></h3><p>DNS 的作⽤就是通过域名查询到具体的 IP。</p><p>因为 IP 存在数字和英⽂的组合（IPv6），很不利于⼈类记忆，所以就出现了域名。你可以把域名看成是某个 IP 的别名，DNS 就是去查询这个别名的真正名称是什么在 TCP 握⼿之前就已经进⾏了 DNS 查询，这个查询是操作系统⾃⼰做的。</p><p>当你在浏览器中想访问 www.google.com 时，会进⾏⼀下操作</p><h4 id="操作系统会首先在本地缓存中查询" tabindex="-1">操作系统会⾸先在本地缓存中查询 <a class="header-anchor" href="#操作系统会首先在本地缓存中查询" aria-label="Permalink to &quot;操作系统会⾸先在本地缓存中查询&quot;">​</a></h4><ul><li>没有的话会去系统配置的 DNS 服务器中查询</li><li>如果这时候还没得话，会直接去 DNS 根服务器查询，这⼀步查询会找出负责 com 这个⼀级域名的服务器</li><li>然后去该服务器查询 google 这个⼆级域名</li><li>接下来三级域名的查询其实是我们配置的，你可以给 www 这个域名配置⼀个 IP，然后还可以给别的三级域名配置⼀个 IP</li></ul><p>以上介绍的是 DNS 迭代查询，还有种是递归查询，区别就是前者是由客户端 去做请求，后者是由系统配置的 DNS 服务器做请求，得到结果后将数据返回 给客户端。</p><h3 id="什么是持久连接" tabindex="-1">什么是持久连接 <a class="header-anchor" href="#什么是持久连接" aria-label="Permalink to &quot;什么是持久连接&quot;">​</a></h3><p>HTTP 协议采用“请求-应答”模式，当使用普通模式，即非 Keep-Alive 模式时，每个请求/应答客户和服务器都要新建一个连接，完成之后立即断开连接 (HTTP 协议为无连接的协议)</p><p>当使用 Keep-Alive 模式 (又称持久连接、连接重用)时，Keep-Alive 功能使客户端到服务器端的连接持续有效，当出现对服务器的后继请求时，Keep-Alive 功能避免了建立或者重新建立连接</p><h3 id="什么是管线化" tabindex="-1">什么是管线化 <a class="header-anchor" href="#什么是管线化" aria-label="Permalink to &quot;什么是管线化&quot;">​</a></h3><p>在使用持久连接的情况下，某个连接上消息的传递类似于：请求 1-&gt; 响应 1-&gt; 请求 2 -&gt; 响应 2-&gt; 请求 3-&gt; 响应 3</p><p>某个连接上的消息变成了类似这样：请求 1 -&gt; 请求 2 -&gt; 请求 3 -&gt; 响应 1-&gt; 响应 2-&gt; 响应 3</p><h4 id="管线化特点" tabindex="-1">管线化特点 <a class="header-anchor" href="#管线化特点" aria-label="Permalink to &quot;管线化特点&quot;">​</a></h4><ul><li>管线化机制通过持久连接完成，仅 HTTP/1.1 支持此技术</li><li>只有 GET 和 HEAD 请求可以进行管线化，而 POST 则有所限制</li><li>初次创建连接时不应启动管线机制，因为对方 (服务器)不一定支持 HTTP/1.1 版本的协议</li><li>管线化不会影响响应到来的顺序，如上面的例子所示，响应返回的顺序并未改变</li><li>HTTP/1.1 要求服务器端支持管线化，但并不要求服务器端也对响应进行管线化处理，只是要求对于管线化的请求不失败即可</li><li>由于上面提到的服务器端问题，开启管线化很可能并不会带来大幅度的性能提升，而且很多服多器端和代理程序对管线化的支持并不好，因此现代浏览器如 Chrome 和 Firefox 默认并未开启管线化支持</li></ul><h2 id="说一下-http2-0" tabindex="-1">说一下 http2.0 <a class="header-anchor" href="#说一下-http2-0" aria-label="Permalink to &quot;说一下 http2.0&quot;">​</a></h2><p>参考回答：</p><p>首先补充一下，http 和 https 的区别，相比于 http,https 是基于 ssl 加密的 http 协议</p><p>简要概括：http2.0 是基于 1999 年发布的 http1.0 之后的首次更新。</p><p>提升访问速度（可以对于，请求资源所需时间更少，访问速度更快，相比 http1.0）</p><p>允许多路复用：多路复用允许同时通过单一的 HTTP/2 连接发送多重请求-响应信息。</p><p>改善了：在 http1.1 中，浏览器客户端在同一时间，针对同一域名下的请求有一定数量限制（连接数量），超过限制会被阻塞。</p><p>二进制分帧：HTTP2.0 会将所有的传输信息分割为更小的信息或者帧，并对他们进行二进制编码、首部压缩、服务器端推送</p><h2 id="http2-0-的特性" tabindex="-1">HTTP2.0 的特性 <a class="header-anchor" href="#http2-0-的特性" aria-label="Permalink to &quot;HTTP2.0 的特性&quot;">​</a></h2><p>参考回答：</p><p>http2.0 的特性如下：</p><p>1、内容安全，应为 http2.0 是基于 https 的，天然具有安全特性，通过 http2.0 的特性可以避免单纯使用 https 的性能下降</p><p>2、二进制格式，http1.X 的解析是基于文本的，http2.0 将所有的传输信息分割为更小的消息和帧，并对他们采用二进制格式编码，基于二进制可以让协议有更多的扩展性，比如引入了帧来传输数据和指令</p><p>3、多路复用，这个功能相当于是长连接的增强，每个 request 请求可以随机的混杂在一起，接收方可以根据 request 的 id 将 request 再归属到各自不同的服务端请求里面，另外多路复用中也支持了流的优先级，允许客户端告诉服务器那些内容是更优先级的资源，可以优先传输。</p><h2 id="http2-0" tabindex="-1">HTTP2.0 <a class="header-anchor" href="#http2-0" aria-label="Permalink to &quot;HTTP2.0&quot;">​</a></h2><p>HTTP/2 很好的解决了当下最常⽤的 HTTP/1 所存在的⼀些性能问题，只需要升级到该协议就可以减少很多之前需要做的性能优化⼯作，当然兼容问题以及如何优雅降级应该是国内还不普遍使⽤的原因之⼀。</p><p>虽然 HTTP/2 已经解决了很多问题，但是并不代表它已经是完美的了，HTTP/3 就是为了解决 HTTP/2 所存在的⼀些问题⽽被推出来的。</p><h3 id="_1-http-2" tabindex="-1">1 HTTP/2 <a class="header-anchor" href="#_1-http-2" aria-label="Permalink to &quot;1 HTTP/2&quot;">​</a></h3><p>HTTP/2 相⽐于 HTTP/1 ，可以说是⼤幅度提⾼了⽹⻚的性能。</p><ul><li>在 HTTP/1 中，为了性能考虑，我们会引⼊雪碧图、将⼩图内联、使⽤多个域名等等的⽅式。这⼀切都是因为浏览器限制了同⼀个域名下的请求数量（Chrome 下⼀般是限制六个连接），当⻚⾯中需要请求很多资源的时候，队头阻塞（Head of line blocking）会导致在达到最⼤请求数量时，剩余的资源需要等待其他资源请求完成后才能发起请求。</li><li>在 HTTP/2 中引⼊了多路复⽤的技术，这个技术可以只通过⼀个 TCP 连接就可以传输所有的请求数据。多路复⽤很好的解决了浏览器限制同⼀个域名下的请求数量的问题，同时也接更容易实现全速传输，毕竟新开⼀个 TCP 连接都需要慢慢提升传输速度。</li></ul><p>⼤家可以通过 该链接：<a href="https://http2.akamai.com/demo" target="_blank" rel="noreferrer">https://http2.akamai.com/demo</a> 感受下 HTTP/2 ⽐ HTTP/1 到底快了多少</p><p>在 HTTP/1 中，因为队头阻塞的原因，你会发现发送请求是⻓这样的</p><p>在 HTTP/2 中，因为可以复⽤同⼀个 TCP 连接，你会发现发送请求是⻓这样的</p><h3 id="_2-二进制传输" tabindex="-1">2 ⼆进制传输 <a class="header-anchor" href="#_2-二进制传输" aria-label="Permalink to &quot;2 ⼆进制传输&quot;">​</a></h3><p>HTTP/2 中所有加强性能的核⼼点在于此。在之前的 HTTP 版本中，我们是 通过⽂本的⽅式传输数据。在 HTTP/2 中引⼊了新的编码机制，所有传输的 数据都会被分割，并采⽤⼆进制格式编码。</p><h3 id="_3-多路复用" tabindex="-1">3 多路复⽤ <a class="header-anchor" href="#_3-多路复用" aria-label="Permalink to &quot;3 多路复⽤&quot;">​</a></h3><p>在 HTTP/2 中，有两个⾮常重要的概念，分别是帧（frame）和流（stream）。</p><p>帧代表着最⼩的数据单位，每个帧会标识出该帧属于哪个流，流也就是多个帧组成的数据流。</p><p>多路复⽤，就是在⼀个 TCP 连接中可以存在多条流。换句话说，也就是可以发送多个请求，对端可以通过帧中的标识知道属于哪个请求。通过这个技术，可以避免 HTTP 旧版本中的队头阻塞问题，极⼤的提⾼传输性能。</p><h3 id="_4-header-压缩" tabindex="-1">4 Header 压缩 <a class="header-anchor" href="#_4-header-压缩" aria-label="Permalink to &quot;4 Header 压缩&quot;">​</a></h3><p>在 HTTP/1 中，我们使⽤⽂本的形式传输 header ，在 header 携带 cookie 的情况下，可能每次都需要重复传输⼏百到⼏千的字节。</p><p>在 HTTP / 2 中，使⽤了 HPACK 压缩格式对传输的 header 进⾏编码，减少了 header 的⼤⼩。并在两端维护了索引表，⽤于记录出现过的 header ，后⾯在传输过程中就可以传输已经记录过的 header 的键名，对端收到数据后就可以通过键名找到对应的值。</p><h3 id="_5-服务端-push" tabindex="-1">5 服务端 Push <a class="header-anchor" href="#_5-服务端-push" aria-label="Permalink to &quot;5 服务端 Push&quot;">​</a></h3><p>在 HTTP/2 中，服务端可以在客户端某个请求后，主动推送其他资源。</p><p>可以想象以下情况，某些资源客户端是⼀定会请求的，这时就可以采取服务端 push 的技术，提前给客户端推送必要的资源，这样就可以相对减少⼀点延迟时间。当然在浏览器兼容的情况下你也可以使⽤ prefetch</p><h2 id="http-3" tabindex="-1">HTTP/3 <a class="header-anchor" href="#http-3" aria-label="Permalink to &quot;HTTP/3&quot;">​</a></h2><p>虽然 HTTP/2 解决了很多之前旧版本的问题，但是它还是存在⼀个巨⼤的问题，虽然这个问题并不是它本身造成的，⽽是底层⽀撑的 TCP 协议的问题。</p><p>因为 HTTP/2 使⽤了多路复⽤，⼀般来说同⼀域名下只需要使⽤⼀个 TCP 连接。当这个连接中出现了丢包的情况，那就会导致 HTTP/2 的表现情况反倒不如 HTTP/1 了。</p><p>因为在出现丢包的情况下，整个 TCP 都要开始等待重传，也就导致了后⾯的所有数据都被阻塞了。但是对于 HTTP/1 来说，可以开启多个 TCP 连接，出现这种情况反到只会影响其中⼀个连接，剩余的 TCP 连接还可以正常传输数据。</p><p>那么可能就会有⼈考虑到去修改 TCP 协议，其实这已经是⼀件不可能完成的任务了。因为TCP 存在的时间实在太⻓，已经充斥在各种设备中，并且这个协议是由操作系统实现的，更新起来不⼤现实。</p><p>基于这个原因，Google 就更起炉灶搞了⼀个基于 UDP 协议的 QUIC 协议，并且使⽤在了 HTTP/3 上，当然 HTTP/3 之前名为 HTTP-over-QUIC ，从这个名字中我们也可以发现，HTTP/3 最⼤的改造就是使⽤了 QUIC ，接下来我们就来学习关于这个协议的内容。</p><h4 id="quic" tabindex="-1">QUIC <a class="header-anchor" href="#quic" aria-label="Permalink to &quot;QUIC&quot;">​</a></h4><p>之前我们学习过 UDP 协议的内容，知道这个协议虽然效率很⾼，但是并不是 那么的可靠。QUIC 虽然基于 UDP，但是在原本的基础上新增了很多功能，⽐ 如多路复⽤、0-RTT、使⽤ TLS1.3 加密、流量控制、有序交付、重传等等功 能。这⾥我们就挑选⼏个重要的功能学习下这个协议的内容。</p><h4 id="多路复用" tabindex="-1">多路复⽤ <a class="header-anchor" href="#多路复用" aria-label="Permalink to &quot;多路复⽤&quot;">​</a></h4><p>虽然 HTTP/2 ⽀持了多路复⽤，但是 TCP 协议终究是没有这个功能的。QUIC 原⽣就实现了这个功能，并且传输的单个数据流可以保证有序交付且不会影响 其他的数据流，这样的技术就解决了之前 TCP 存在的问题。</p><p>并且 QUIC 在移动端的表现也会⽐ TCP 好。因为 TCP 是基于 IP 和端⼝去识别连接的，这种⽅式在多变的移动端⽹络环境下是很脆弱的。但是 QUIC 是通过 ID 的⽅式去识别⼀个连接，不管你⽹络环境如何变化，只要 ID 不变，就能迅速重连上。</p><h4 id="_0-rtt" tabindex="-1">0-RTT <a class="header-anchor" href="#_0-rtt" aria-label="Permalink to &quot;0-RTT&quot;">​</a></h4><p>通过使⽤类似 TCP 快速打开的技术，缓存当前会话的上下⽂，在下次恢复会 话的时候，只需要将之前的缓存传递给服务端验证通过就可以进⾏传输了。</p><h4 id="纠错机制" tabindex="-1">纠错机制 <a class="header-anchor" href="#纠错机制" aria-label="Permalink to &quot;纠错机制&quot;">​</a></h4><p>假如说这次我要发送三个包，那么协议会算出这三个包的异或值并单独发出⼀个校验包，也就是总共发出了四个包。</p><p>当出现其中的⾮校验包丢包的情况时，可以通过另外三个包计算出丢失的数据包的内容。</p><p>当然这种技术只能使⽤在丢失⼀个包的情况下，如果出现丢失多个包就不能使⽤纠错机制了，只能使⽤重传的⽅式了</p><h2 id="说一下-http-和-https" tabindex="-1">说一下 http 和 https <a class="header-anchor" href="#说一下-http-和-https" aria-label="Permalink to &quot;说一下 http 和 https&quot;">​</a></h2><p>参考回答：</p><p>https 的 SSL 加密是在传输层实现的。</p><h3 id="_1-http-和-https-的基本概念" tabindex="-1">(1)http 和 https 的基本概念 <a class="header-anchor" href="#_1-http-和-https-的基本概念" aria-label="Permalink to &quot;(1)http 和 https 的基本概念&quot;">​</a></h3><ul><li>http: 超文本传输协议，是互联网上应用最为广泛的一种网络协议，是一个客户端和服务器端请求和应答的标准（TCP），用于从 WWW 服务器传输超文本到本地浏览器的传输协议，它可以使浏览器更加高效，使网络传输减少。</li><li>https: 是以安全为目标的 HTTP 通道，简单讲是 HTTP 的安全版，即 HTTP 下加入 SSL层，HTTPS 的安全基础是 SSL，因此加密的详细内容就需要 SSL。</li><li>https 协议的主要作用是：建立一个信息安全通道，来确保数组的传输，确保网站的真实性。</li></ul><h3 id="_2-http-和-https-的区别" tabindex="-1">(2)http 和 https 的区别？ <a class="header-anchor" href="#_2-http-和-https-的区别" aria-label="Permalink to &quot;(2)http 和 https 的区别？&quot;">​</a></h3><p>http 传输的数据都是未加密的，也就是明文的，网景公司设置了 SSL 协议来对 http 协议传输的数据进行加密处理，简单来说 https 协议是由 http 和 ssl 协议构建的可进行加密传输和身份认证的网络协议，比 http 协议的安全性更高。</p><p>主要的区别如下：</p><ul><li>Https 协议需要 ca 证书，费用较高。</li><li>http 是超文本传输协议，信息是明文传输，https 则是具有安全性的 ssl 加密传输协议。</li><li>使用不同的链接方式，端口也不同，一般而言，http 协议的端口为 80，https 的端口为 443</li><li>http 的连接很简单，是无状态的；HTTPS 协议是由 SSL+HTTP 协议构建的可进行加密传输、身份认证的网络协议，比 http 协议安全。</li></ul><h3 id="_3-https-协议的工作原理" tabindex="-1">(3)https 协议的工作原理 <a class="header-anchor" href="#_3-https-协议的工作原理" aria-label="Permalink to &quot;(3)https 协议的工作原理&quot;">​</a></h3><p>客户端在使用 HTTPS 方式与 Web 服务器通信时有以下几个步骤，如图所示。</p><p>客户使用 https url 访问服务器，则要求 web 服务器建立 ssl 链接。</p><p>web 服务器接收到客户端的请求之后，会将网站的证书（证书中包含了公钥），返回或者说传输给客户端。</p><p>客户端和 web 服务器端开始协商 SSL 链接的安全等级，也就是加密等级。</p><p>客户端浏览器通过双方协商一致的安全等级，建立会话密钥，然后通过网站的公钥来加密会话密钥，并传送给网站。</p><p>web 服务器通过自己的私钥解密出会话密钥。</p><p>web 服务器通过会话密钥加密与客户端之间的通信。</p><h3 id="_4-https-协议的优点" tabindex="-1">(4)https 协议的优点 <a class="header-anchor" href="#_4-https-协议的优点" aria-label="Permalink to &quot;(4)https 协议的优点&quot;">​</a></h3><p>使用 HTTPS 协议可认证用户和服务器，确保数据发送到正确的客户机和服务器；</p><p>HTTPS 协议是由 SSL+HTTP 协议构建的可进行加密传输、身份认证的网络协议，要比http 协议安全，可防止数据在传输过程中不被窃取、改变，确保数据的完整性。</p><p>HTTPS 是现行架构下最安全的解决方案，虽然不是绝对安全，但它大幅增加了中间人攻击的成本。</p><p>谷歌曾在 2014 年 8 月份调整搜索引擎算法，并称“比起同等 HTTP 网站，采用 HTTPS加密的网站在搜索结果中的排名将会更高”。</p><h3 id="_5-https-协议的缺点" tabindex="-1">(5)https 协议的缺点 <a class="header-anchor" href="#_5-https-协议的缺点" aria-label="Permalink to &quot;(5)https 协议的缺点&quot;">​</a></h3><p>https 握手阶段比较费时，会使页面加载时间延长 50%，增加 10%~20%的耗电。</p><p>https 缓存不如 http 高效，会增加数据开销。</p><p>SSL 证书也需要钱，功能越强大的证书费用越高。</p><p>SSL 证书需要绑定 IP，不能再同一个 ip 上绑定多个域名，ipv4 资源支持不了这种消耗。</p><h2 id="tcp-ip-通信协议" tabindex="-1">TCP/IP 通信协议 <a class="header-anchor" href="#tcp-ip-通信协议" aria-label="Permalink to &quot;TCP/IP 通信协议&quot;">​</a></h2><h3 id="tcp-三次握手-一句话概括" tabindex="-1">tcp 三次握手，一句话概括 <a class="header-anchor" href="#tcp-三次握手-一句话概括" aria-label="Permalink to &quot;tcp 三次握手，一句话概括&quot;">​</a></h3><p>参考回答：</p><p>客户端和服务端都需要直到各自可收发，因此需要三次握手。</p><p>简化三次握手：</p><p><img src="'+l+`" alt="三次握手"></p><p>从图片可以得到三次握手可以简化为：</p><p>C 发起请求连接 S 确认，也发起连接 C 确认</p><p>我们再看看每次握手的作用：</p><ul><li>第一次握手：S 只可以确认 自己可以接受 C 发送的报文段</li><li>第二次握手：C 可以确认 S 收到了自己发送的报文段，并且可以确认 自己可以接受 S 发送的报文段</li><li>第三次握手：S 可以确认 C 收到了自己发送的报文段</li></ul><h3 id="说下-tcp-握手和挥手过程" tabindex="-1">说下 TCP 握⼿和挥⼿过程 <a class="header-anchor" href="#说下-tcp-握手和挥手过程" aria-label="Permalink to &quot;说下 TCP 握⼿和挥⼿过程&quot;">​</a></h3><p>三次握⼿，五次挥⼿，每㇐次的⽬的要知道</p><h3 id="http-1-1-的队头阻塞问题编解码-加密-base64" tabindex="-1">HTTP 1.1 的队头阻塞问题编解码/加密 base64 <a class="header-anchor" href="#http-1-1-的队头阻塞问题编解码-加密-base64" aria-label="Permalink to &quot;HTTP 1.1 的队头阻塞问题编解码/加密 base64&quot;">​</a></h3><p>encodeURIComponent / decodeURIComponent 对称加密</p><h3 id="非对称加密数字签名-验签" tabindex="-1">非对称加密数字签名/验签 <a class="header-anchor" href="#非对称加密数字签名-验签" aria-label="Permalink to &quot;非对称加密数字签名/验签&quot;">​</a></h3><h3 id="头部" tabindex="-1">头部 <a class="header-anchor" href="#头部" aria-label="Permalink to &quot;头部&quot;">​</a></h3><p>TCP 头部⽐ UDP 头部复杂的多</p><p>对于 TCP 头部来说，以下⼏个字段是很重要的</p><ul><li>Sequence number ，这个序号保证了 TCP 传输的报⽂都是有序的，对端可以通过序号顺序的拼接报⽂</li><li>Acknowledgement Number ，这个序号表示数据接收端期望接收的下⼀个字节的编号是多少，同时也表示上⼀个序号的数据已经收到</li><li>Window Size ，窗⼝⼤⼩，表示还能接收多少字节的数据，⽤于流量控制</li></ul><h4 id="标识符" tabindex="-1">标识符 <a class="header-anchor" href="#标识符" aria-label="Permalink to &quot;标识符&quot;">​</a></h4><ul><li>URG=1 ：该字段为⼀表示本数据报的数据部分包含紧急信息，是⼀个⾼优先级数据报⽂，此时紧急指针有效。紧急数据⼀定位于当前数据包数据部分的最前⾯，紧急指针标明了紧急数据的尾部。</li><li>ACK=1 ：该字段为⼀表示确认号字段有效。此外， TCP 还规定在连接建⽴后传送的所有报⽂段都必须把 ACK 置为⼀ PSH=1 ：该字段为⼀表示接收端应该⽴即将数据 push 给应⽤层，⽽不是等到缓冲区满后再提交。</li><li>RST=1 ：该字段为⼀表示当前 TCP 连接出现严重问题，可能需要重新建⽴ TCP 连接，也可以⽤于拒绝⾮法的报⽂段和拒绝连接请求。</li><li>SYN=1 ：当 SYN=1 ， ACK=0 时，表示当前报⽂段是⼀个连接请求报⽂。当 SYN=1 ，ACK=1 时，表示当前报⽂段是⼀个同意建⽴连接的应答报⽂。</li><li>FIN=1 ：该字段为⼀表示此报⽂段是⼀个释放连接的请求报⽂</li></ul><h3 id="状态机" tabindex="-1">状态机 <a class="header-anchor" href="#状态机" aria-label="Permalink to &quot;状态机&quot;">​</a></h3><p>HTTP 是⽆连接的，所以作为下层的 TCP 协议也是⽆连接的，虽然看似TCP 将两端连接了起来，但是其实只是两端共同维护了⼀个状态</p><ul><li>TCP 的状态机是很复杂的，并且与建⽴断开连接时的握⼿息息相关，接下来就来详细描述下两种握⼿。</li><li>在这之前需要了解⼀个重要的性能指标 RTT。该指标表示发送端发送数据到接收到对端数据所需的往返时间</li></ul><h4 id="建立连接三次握手" tabindex="-1">建⽴连接三次握⼿ <a class="header-anchor" href="#建立连接三次握手" aria-label="Permalink to &quot;建⽴连接三次握⼿&quot;">​</a></h4><ul><li>在 TCP 协议中，主动发起请求的⼀端为客户端，被动连接的⼀端称为服务端。不管是客户端还是服务端， TCP 连接建⽴完后都能发送和接收数据，所以 TCP 也是⼀个全双⼯的协议。</li><li>起初，两端都为 CLOSED 状态。在通信开始前，双⽅都会创建 TCB 。 服务器创建完TCB 后遍进⼊ LISTEN 状态，此时开始等待客户端发送数据</li></ul><h5 id="第一次握手" tabindex="-1">第⼀次握⼿ <a class="header-anchor" href="#第一次握手" aria-label="Permalink to &quot;第⼀次握⼿&quot;">​</a></h5><p>客户端向服务端发送连接请求报⽂段。该报⽂段中包含⾃身的数据通讯初始序 号。请求发送后，客户端便进⼊ SYN-SENT 状态，x 表示客户端的数据通信初 始序号。</p><h5 id="第二次握手" tabindex="-1">第⼆次握⼿ <a class="header-anchor" href="#第二次握手" aria-label="Permalink to &quot;第⼆次握⼿&quot;">​</a></h5><p>服务端收到连接请求报⽂段后，如果同意连接，则会发送⼀个应答，该应答中 也会包含⾃身的数据通讯初始序号，发送完成后便进⼊ SYN-RECEIVED 状态。</p><h5 id="第三次握手" tabindex="-1">第三次握⼿ <a class="header-anchor" href="#第三次握手" aria-label="Permalink to &quot;第三次握⼿&quot;">​</a></h5><p>当客户端收到连接同意的应答后，还要向服务端发送⼀个确认报⽂。客户端发 完这个报⽂段后便进⼊ ESTABLISHED 状态，服务端收到这个应答后也进⼊ESTABLISHED 状态，此时连接建⽴成功。</p><p><strong>PS</strong>：第三次握⼿可以包含数据，通过 TCP 快速打开（ TFO ）技术。其实只要涉及到握⼿的协议，都可以使⽤类似 TFO 的⽅式，客户端和服务端存储相同 cookie ，下次握⼿时发出 cookie 达到减少 RTT 的⽬的</p><h4 id="你是否有疑惑明明两次握手就可以建立起连接-为什么还需要第三次应答" tabindex="-1">你是否有疑惑明明两次握⼿就可以建⽴起连接，为什么还需要第三次应答？ <a class="header-anchor" href="#你是否有疑惑明明两次握手就可以建立起连接-为什么还需要第三次应答" aria-label="Permalink to &quot;你是否有疑惑明明两次握⼿就可以建⽴起连接，为什么还需要第三次应答？&quot;">​</a></h4><p>因为这是为了防⽌失效的连接请求报⽂段被服务端接收，从⽽产⽣错误</p><p>可以想象如下场景。客户端发送了⼀个连接请求 A，但是因为⽹络原因造成了超时，这时 TCP 会启动超时重传的机制再次发送⼀个连接请求 B。此时请求顺 利到达服务端，服务端应答完就建⽴了请求。如果连接请求 A 在两端关闭后终 于抵达了服务端，那么这时服务端会认为客户端⼜需要建⽴ TCP 连接，从⽽应答了该请求并进⼊ ESTABLISHED 状态。此时客户端其实是 CLOSED 状态，那么就会导致服务端⼀直等待，造成资源的浪费</p><p>PS：在建⽴连接中，任意⼀端掉线，TCP 都会重发 SYN 包，⼀般会重试五 次，在建⽴连接中可能会遇到 SYN FLOOD 攻击。遇到这种情况你可以选择调 低重试次数或者⼲脆在不能处理的情况下拒绝请求</p><h4 id="断开链接四次握手" tabindex="-1">断开链接四次握⼿ <a class="header-anchor" href="#断开链接四次握手" aria-label="Permalink to &quot;断开链接四次握⼿&quot;">​</a></h4><p>TCP 是全双⼯的，在断开连接时两端都需要发送 FIN 和 ACK 。</p><h5 id="第一次握手-1" tabindex="-1">第⼀次握⼿ <a class="header-anchor" href="#第一次握手-1" aria-label="Permalink to &quot;第⼀次握⼿&quot;">​</a></h5><p>若客户端 A 认为数据发送完成，则它需要向服务端 B 发送连接释放请求。</p><h5 id="第二次握手-1" tabindex="-1">第⼆次握⼿ <a class="header-anchor" href="#第二次握手-1" aria-label="Permalink to &quot;第⼆次握⼿&quot;">​</a></h5><p>B 收到连接释放请求后，会告诉应⽤层要释放 TCP 链接。然后会发送 ACK包，并进⼊ CLOSE_WAIT 状态，表示 A 到 B 的连接已经释放，不接收 A 发的数据了。但是因为 TCP 连接时双向的，所以 B 仍旧可以发送数据给 A。</p><h5 id="第三次握手-1" tabindex="-1">第三次握⼿ <a class="header-anchor" href="#第三次握手-1" aria-label="Permalink to &quot;第三次握⼿&quot;">​</a></h5><p>B 如果此时还有没发完的数据会继续发送，完毕后会向 A 发送连接释放请求， 然后 B 便进⼊ LAST-ACK 状态。</p><p>PS：通过延迟确认的技术（通常有时间限制，否则对⽅会误认为需要重传）， 可以将第⼆次和第三次握⼿合并，延迟 ACK 包的发送。</p><h5 id="第四次握手" tabindex="-1">第四次握⼿ <a class="header-anchor" href="#第四次握手" aria-label="Permalink to &quot;第四次握⼿&quot;">​</a></h5><p>A 收到释放请求后，向 B 发送确认应答，此时 A 进⼊ TIME-WAIT 状态。该状态会持续2MSL（最⼤段⽣存期，指报⽂段在⽹络中⽣存的时间，超时会被抛弃） 时间，若该时间段内没有 B 的重发请求的话，就进⼊ CLOSED 状态。当 B 收到确认应答后，也便进⼊CLOSED 状态。</p><h6 id="为什么-a-要进入-time-wait-状态-等待-2msl-时间后才进入-closed-状态" tabindex="-1">为什么 A 要进⼊ TIME-WAIT 状态，等待 2MSL 时间后才进⼊ CLOSED 状态？ <a class="header-anchor" href="#为什么-a-要进入-time-wait-状态-等待-2msl-时间后才进入-closed-状态" aria-label="Permalink to &quot;为什么 A 要进⼊ TIME-WAIT 状态，等待 2MSL 时间后才进⼊ CLOSED 状态？&quot;">​</a></h6><p>为了保证 B 能收到 A 的确认应答。若 A 发完确认应答后直接进⼊ CLOSED 状态，如果确认应答因为⽹络问题⼀直没有到达，那么会造成 B 不能正常关闭</p><h2 id="tcp-和-udp-的区别" tabindex="-1">TCP 和 UDP 的区别 <a class="header-anchor" href="#tcp-和-udp-的区别" aria-label="Permalink to &quot;TCP 和 UDP 的区别&quot;">​</a></h2><p>参考回答：</p><ul><li>（1）TCP 是面向连接的，udp 是无连接的即发送数据前不需要先建立链接。</li><li>（2）TCP 提供可靠的服务。也就是说，通过 TCP 连接传送的数据，无差错，不丢失，不重复，且按序到达;UDP 尽最大努力交付，即不保证可靠交付。 并且因为 tcp 可靠，面向连接，不会丢失数据因此适合大数据量的交换。</li><li>（3）TCP 是面向字节流，UDP 面向报文，并且网络出现拥塞不会使得发送速率降低（因此会出现丢包，对实时的应用比如 IP 电话和视频会议等）。</li><li>（4）TCP 只能是 1 对 1 的，UDP 支持 1 对 1,1 对多。</li><li>（5）TCP 的首部较大为 20 字节，而 UDP 只有 8 字节。</li><li>（6）TCP 是面向连接的可靠性传输，而 UDP 是不可靠的。</li></ul><h2 id="udp" tabindex="-1">UDP <a class="header-anchor" href="#udp" aria-label="Permalink to &quot;UDP&quot;">​</a></h2><h3 id="_1-1-面向报文" tabindex="-1">1.1 面向报文 <a class="header-anchor" href="#_1-1-面向报文" aria-label="Permalink to &quot;1.1 面向报文&quot;">​</a></h3><p>UDP 是一个面向报文（报文可以理解为一段段的数据）的协议。意思就是UDP 只是报文的搬运工，不会对报文进行任何拆分和拼接操作</p><p>具体来说</p><ul><li>在发送端，应用层将数据传递给传输层的 UDP 协议， UDP 只会给数据增加一个 UDP头标识下是 UDP 协议，然后就传递给网络层了</li><li>在接收端，网络层将数据传递给传输层， UDP 只去除 IP 报文头就传递给应用层，不会任何拼接操作</li></ul><h3 id="_1-2-不可靠性" tabindex="-1">1.2 不可靠性 <a class="header-anchor" href="#_1-2-不可靠性" aria-label="Permalink to &quot;1.2 不可靠性&quot;">​</a></h3><ul><li>UDP 是无连接的，也就是说通信不需要建立和断开连接。</li><li>UDP 也是不可靠的。协议收到什么数据就传递什么数据，并且也不会备份数据，对方能不能收到是不关心的</li><li>UDP 没有拥塞控制，一直会以恒定的速度发送数据。即使网络条件不好，也不会对发送速率进行调整。这样实现的弊端就是在网络条件不好的情况下可能会导致丢包，但是优点也很明显，在某些实时性要求高的场景（比如电话会议）就需要使用 UDP 而不是 TCP</li></ul><h3 id="_1-3-高效" tabindex="-1">1.3 高效 <a class="header-anchor" href="#_1-3-高效" aria-label="Permalink to &quot;1.3 高效&quot;">​</a></h3><p>因为 UDP 没有 TCP 那么复杂，需要保证数据不丢失且有序到达。所以 UDP 的头部开销小，只有八字节，相比 TCP 的至少二十字节要少得多，在传输数据报文时是很高效的</p><h4 id="头部包含了以下几个数据" tabindex="-1">头部包含了以下几个数据 <a class="header-anchor" href="#头部包含了以下几个数据" aria-label="Permalink to &quot;头部包含了以下几个数据&quot;">​</a></h4><ul><li>两个十六位的端口号，分别为源端口（可选字段）和目标端口 整个数据报文的⻓度</li><li>整个数据报文的检验和（ IPv4 可选 字段），该字段用于发现头部信息和数据中的错误</li></ul><h3 id="_1-4-传输方式" tabindex="-1">1.4 传输方式 <a class="header-anchor" href="#_1-4-传输方式" aria-label="Permalink to &quot;1.4 传输方式&quot;">​</a></h3><p>UDP 不止支持一对一的传输方式，同样支持一对多，多对多，多对一的方式，也就是说 UDP 提供了单播，多播，广播的功能</p><h2 id="websocket-的实现和应用" tabindex="-1">WebSocket 的实现和应用 <a class="header-anchor" href="#websocket-的实现和应用" aria-label="Permalink to &quot;WebSocket 的实现和应用&quot;">​</a></h2><p>参考回答：</p><h3 id="_1-什么是-websocket" tabindex="-1">(1)什么是 WebSocket? <a class="header-anchor" href="#_1-什么是-websocket" aria-label="Permalink to &quot;(1)什么是 WebSocket?&quot;">​</a></h3><p>WebSocket 是 HTML5 中的协议，支持持久连续，http 协议不支持持久性连接。Http1.0和 HTTP1.1 都不支持持久性的链接，HTTP1.1 中的 keep-alive，将多个 http 请求合并为 1 个</p><h3 id="_2-websocket-是什么样的协议-具体有什么优点" tabindex="-1">(2)WebSocket 是什么样的协议，具体有什么优点？ <a class="header-anchor" href="#_2-websocket-是什么样的协议-具体有什么优点" aria-label="Permalink to &quot;(2)WebSocket 是什么样的协议，具体有什么优点？&quot;">​</a></h3><p>HTTP 的生命周期通过 Request 来界定，也就是 Request 一个 Response，那么在Http1.0 协议中，这次 Http 请求就结束了。在 Http1.1 中进行了改进，是的有一个connection：Keep-alive，也就是说，在一个 Http 连接中，可以发送多个 Request，接收多个 Response。但是必须记住，在 Http 中一个 Request 只能对应有一个Response，而且这个 Response 是被动的，不能主动发起。</p><p>WebSocket 是基于 Http 协议的，或者说借用了 Http 协议来完成一部分握手，在握手阶段与 Http 是相同的。我们来看一个 websocket 握手协议的实现，基本是 2 个属性，upgrade，connection。</p><p>基本请求如下：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">GET</span><span style="color:#98C379;"> /chat</span><span style="color:#98C379;"> HTTP/1.1</span></span>
<span class="line"><span style="color:#61AFEF;">Host:</span><span style="color:#98C379;"> server.example.com</span></span>
<span class="line"><span style="color:#61AFEF;">Upgrade:</span><span style="color:#98C379;"> websocket</span></span>
<span class="line"><span style="color:#61AFEF;">Connection:</span><span style="color:#98C379;"> Upgrade</span></span>
<span class="line"><span style="color:#61AFEF;">Sec-WebSocket-Key:</span><span style="color:#98C379;"> x3JJHMbDL1EzLkh9GBhXDw==</span></span>
<span class="line"><span style="color:#61AFEF;">Sec-WebSocket-Protocol:</span><span style="color:#98C379;"> chat,</span><span style="color:#98C379;"> superchat</span></span>
<span class="line"><span style="color:#61AFEF;">Sec-WebSocket-Version:</span><span style="color:#D19A66;"> 13</span></span>
<span class="line"><span style="color:#61AFEF;">Origin:</span><span style="color:#98C379;"> http://example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>多了下面 2 个属性：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">Upgrade:webSocket</span></span>
<span class="line"><span style="color:#61AFEF;">Connection:Upgrade</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>告诉服务器发送的是 websocket</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">Sec-WebSocket-Key:</span><span style="color:#98C379;"> x3JJHMbDL1EzLkh9GBhXDw==</span></span>
<span class="line"><span style="color:#61AFEF;">Sec-WebSocket-Protocol:</span><span style="color:#98C379;"> chat,</span><span style="color:#98C379;"> superchat</span></span>
<span class="line"><span style="color:#61AFEF;">Sec-WebSocket-Version:</span><span style="color:#D19A66;"> 13</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="一个图片-url-访问后直接下载怎样实现" tabindex="-1">一个图片 url 访问后直接下载怎样实现？ <a class="header-anchor" href="#一个图片-url-访问后直接下载怎样实现" aria-label="Permalink to &quot;一个图片 url 访问后直接下载怎样实现？&quot;">​</a></h2><p>参考回答： 请求的返回头里面，用于浏览器解析的重要参数就是 OSS 的 API 文档里面的返回 http头，决定用户下载行为的参数。</p><p>下载的情况下：</p><ol><li>x-oss-object-type: Normal</li><li>x-oss-request-id: 598D5ED34F29D01FE2925F41</li><li>x-oss-storage-class: Standard</li></ol><h2 id="cookie" tabindex="-1">cookie <a class="header-anchor" href="#cookie" aria-label="Permalink to &quot;cookie&quot;">​</a></h2><p>HTTP 协议本身是⽆状态的，⽽ Cookie 是在 HTTP 中的㇐个请求头，用来保存㇐小块数据，Cookie 会传递到服务端，用来作为会话标识。服务端可以通过 Set-Cookie 来设置 cookie，⽽客户端⽹⻚ 也可以通过 document.cookie 来操作 cookie。</p><h3 id="document-操作-cookie" tabindex="-1">document 操作 cookie <a class="header-anchor" href="#document-操作-cookie" aria-label="Permalink to &quot;document 操作 cookie&quot;">​</a></h3><p>需要问 AI 完善.....</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E5C07B;">document</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">cookie</span><span style="color:#ABB2BF;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="cookie-的过期控制" tabindex="-1">cookie 的过期控制 <a class="header-anchor" href="#cookie-的过期控制" aria-label="Permalink to &quot;cookie 的过期控制&quot;">​</a></h3><p>cookie 可以通过 max-age 和 expires 控制过期时间，如果不设置过期时间，cookie 会在浏览器完全关闭时失效。</p><h3 id="防止-cookie-被-javascript-脚本操作" tabindex="-1">防⽌ cookie 被 javascript 脚本操作 <a class="header-anchor" href="#防止-cookie-被-javascript-脚本操作" aria-label="Permalink to &quot;防⽌ cookie 被 javascript 脚本操作&quot;">​</a></h3><p>可以在 Set-Cookie 时使用 HttpOnly 控制。㇐定程度上缓解 XSS 攻击</p><h3 id="服务端-set-cookie" tabindex="-1">服务端 Set-Cookie <a class="header-anchor" href="#服务端-set-cookie" aria-label="Permalink to &quot;服务端 Set-Cookie&quot;">​</a></h3><p>㇐个 Set-Cookie 也只能设置㇐个 cookie，如果需要设置多个，则返回多个 Set-Cookie 头。</p><p>Set-Cookie 和 document.cookie 操作类似，但是要注意两个选项，分别是 HttpOnly 和 SameSite， HttpOnly 在上㇐小节说过了。SameSite 则是预防 CSRF 攻击的㇐种⼿段，允许服务器要求某个 cookie 在跨站请求时不会被发送。</p><p>● SameSite=Strict：跨站请求时，不携带 cookie。 ● SameSite=Lax：宽松的，跨站请求时，也不会携带 cookie。但是从外部站点导航到本站点时会携带 cookie。Lax 是⾼版本 Chrome（80 版本以上）的 默认设置。</p><p>Lax 保证了这种场景可用：⽐如你在 github 已经登录过了，现在希望通过另外㇐个⽹站的链接跳转到 github，并且能保持 gitlab 的登录态，就需要用到 Lax。⽽ Strict 会阻⽌这㇐⾏为，这可能会 要求你重新登录 github。</p><p>● SameSite=None：不做限制，跨站请求时，会携带 cookie。使用 SameSite=None 时，需要配合 Secure 使用，也就是要求 Https 协议下才能使用 None。</p><h3 id="跨站-cookie" tabindex="-1">跨站 cookie <a class="header-anchor" href="#跨站-cookie" aria-label="Permalink to &quot;跨站 cookie&quot;">​</a></h3><p>恶意的跨站传递 cookie</p><p>在被恶意注⼊的情况下（⽐如 XSS），就可能导致本站点的 cookie 泄露。⽐如㇐个论坛留⾔板块，被 XSS 注⼊了㇐段脚本，脚本会动态加载㇐张图⽚，图⽚的地址可能是⿊客服务。</p><p>这样㇐来，只要用户打开留⾔板块，⾃⼰的 cookie 信息就泄露了，就有可能被⿊客冒充身份，造成损失。</p><h3 id="业务需要的共享-cookie" tabindex="-1">业务需要的共享 cookie <a class="header-anchor" href="#业务需要的共享-cookie" aria-label="Permalink to &quot;业务需要的共享 cookie&quot;">​</a></h3><p>为了满⾜类似于单点登录这样的功能，我们在统㇐认证平台 authgateway.myenterprise.com 登录后，希望公司内部另㇐个站点 other.myenterprise.com 也能共享这种登录状态。那么服务器端在 authgateway.myenterprise.com 登录成功后，应该 Set-Cookie 时将 domain 部分设置为 myenterprise.com，这样 myenterprise.com 的各个⼦域名才能共享登录状态。</p><p>但是这样也有⻛险，㇐旦某个⼦站被 XSS，就有可能全部被攻击（Cookie 作用域攻击）。最好启用全站 HTTPS+Secure，也必须适当缩小 cookie 的作用域 （限制 domain 和 path）。</p><h3 id="cookie-篡改" tabindex="-1">cookie 篡改 <a class="header-anchor" href="#cookie-篡改" aria-label="Permalink to &quot;cookie 篡改&quot;">​</a></h3><p>这个就很好理解了，document.cookie 是可以操作 cookie 的，这就留下了㇐些隐患，对于关键 cookie 信息，必须启用 HttpOnly 防护。</p><h3 id="cookie-劫持" tabindex="-1">cookie 劫持 <a class="header-anchor" href="#cookie-劫持" aria-label="Permalink to &quot;cookie 劫持&quot;">​</a></h3><p>如果没有 HTTPS 证书的保障，cookie 也是明文传输，相当于裸奔。除了 XSS 攻击劫持 cookie，攻击者还可以通过中间⼈攻击获取 HTTP 报文中的 cookie。对于这些劫持情况，应该对 cookie 加密/ 签名或者采用 Https 防范！强缓存和协商缓存</p><h2 id="cookie-和-session-的区别-localstorage-和-sessionstorage-的区别" tabindex="-1">cookie 和 session 的区别，localstorage 和 sessionstorage 的区别 <a class="header-anchor" href="#cookie-和-session-的区别-localstorage-和-sessionstorage-的区别" aria-label="Permalink to &quot;cookie 和 session 的区别，localstorage 和 sessionstorage 的区别&quot;">​</a></h2><p>参考回答：</p><p>Cookie 和 session 都可用来存储用户信息，cookie 存放于客户端，session 存放于服务器端，因为 cookie 存放于客户端有可能被窃取，所以 cookie 一般用来存放不敏感的信息，比如用户设置的网站主题，敏感的信息用 session 存储，比如用户的登陆信息，session 可以存放于文件，数据库，内存中都可以，cookie 可以服务器端响应的时候设置，也可以客户端通过 JS 设置 cookie 会在请求时在 http 首部发送给客户端，cookie 一般在客户端有大小限制，一般为 4K，</p><h3 id="下面从几个方向区分一下-cookie-localstorage-sessionstorage-的区别" tabindex="-1">下面从几个方向区分一下 cookie，localstorage，sessionstorage 的区别 <a class="header-anchor" href="#下面从几个方向区分一下-cookie-localstorage-sessionstorage-的区别" aria-label="Permalink to &quot;下面从几个方向区分一下 cookie，localstorage，sessionstorage 的区别&quot;">​</a></h3><p>1、生命周期：</p><ul><li>Cookie：可设置失效时间，否则默认为关闭浏览器后失效</li><li>Localstorage:除非被手动清除，否则永久保存</li><li>Sessionstorage：仅在当前网页会话下有效，关闭页面或浏览器后就会被清除</li></ul><p>2、存放数据：</p><ul><li>Cookie：4k 左右</li><li>Localstorage 和 sessionstorage：可以保存 5M 的信息</li></ul><p>3、http 请求：</p><ul><li>Cookie：每次都会携带在 http 头中，如果使用 cookie 保存过多数据会带来性能问题</li><li>其他两个：仅在客户端即浏览器中保存，不参与和服务器的通信</li></ul><p>4、易用性：</p><ul><li>Cookie：需要程序员自己封装，原生的 cookie 接口不友好</li><li>其他两个：即可采用原生接口，亦可再次封装</li></ul><p>5、应用场景：</p><p>从安全性来说，因为每次 http 请求都回携带 cookie 信息，这样子浪费了带宽，所以cookie 应该尽可能的少用，此外 cookie 还需要指定作用域，不可以跨域调用，限制很多，但是用户识别用户登陆来说，cookie 还是比 storage 好用，其他情况下可以用storage，localstorage 可以用来在页面传递参数，sessionstorage 可以用来保存一些临时的数据，防止用户刷新页面后丢失了一些参数。</p><h2 id="cookie、sessionstorage、localstorage-的区别" tabindex="-1">Cookie、sessionStorage、localStorage 的区别 <a class="header-anchor" href="#cookie、sessionstorage、localstorage-的区别" aria-label="Permalink to &quot;Cookie、sessionStorage、localStorage 的区别&quot;">​</a></h2><p>参考回答：</p><p>共同点：都是保存在浏览器端，并且是同源的</p><p>Cookie：cookie 数据始终在同源的 http 请求中携带（即使不需要），即 cookie 在浏览器和服务器间来回传递。而 sessionStorage 和 localStorage 不会自动把数据发给服务器，仅在本地保存。cookie 数据还有路径（path）的概念，可以限制 cookie 只属于某个路径下,存储的大小很小只有 4K 左右。（key：可以在浏览器和服务器端来回传递，存储容量小，只有大约 4K 左右）</p><p>sessionStorage：仅在当前浏览器窗口关闭前有效，自然也就不可能持久保持，localStorage：始终有效，窗口或浏览器关闭也一直保存，因此用作持久数据；</p><p>cookie 只在设置的 cookie 过期时间之前一直有效，即使窗口或浏览器关闭。（key：本身就是一个回话过程，关闭浏览器后消失，session 为一个回话，当页面不同即使是同一页面打开两次，也被视为同一次回话）</p><p>localStorage：localStorage 在所有同源窗口中都是共享的；cookie 也是在所有同源窗口中都是共享的。（key：同源窗口都会共享，并且不会失效，不管窗口或者浏览器关闭与否都会始终生效）</p><h3 id="补充说明一下-cookie-的作用" tabindex="-1">补充说明一下 cookie 的作用： <a class="header-anchor" href="#补充说明一下-cookie-的作用" aria-label="Permalink to &quot;补充说明一下 cookie 的作用：&quot;">​</a></h3><h4 id="保存用户登录状态" tabindex="-1">保存用户登录状态 <a class="header-anchor" href="#保存用户登录状态" aria-label="Permalink to &quot;保存用户登录状态&quot;">​</a></h4><p>例如将用户 id 存储于一个 cookie 内，这样当用户下次访问该页面时就不需要重新登录了，现在很多论坛和社区都提供这样的功能。 cookie 还可以设置过期时间，当超过时间期限后，cookie 就会自动消失。因此，系统往往可以提示用户保持登录状态的时间：常见选项有一个月、三个 月、一年等。</p><h4 id="跟踪用户行为" tabindex="-1">跟踪用户行为 <a class="header-anchor" href="#跟踪用户行为" aria-label="Permalink to &quot;跟踪用户行为&quot;">​</a></h4><p>例如一个天气预报网站，能够根据用户选择的地区显示当地的天气情况。如果每次都需要选择所在地是烦琐的，当利用了 cookie 后就会显得很人性化了， 系统能够记住上一次访问的地区，当下次再打开该页面时，它就会自动显示上次用户所在地区的天气情况。因为一切都是在后 台完成，所以这样的页面就像为某个用户所定制的一样，使用起来非常方便定制页面。如果网站提供了换肤或更换布局的功能，那么可以使用 cookie 来记录用户的选项，例如：背景色、分辨率等。当用户下次访问时，仍然可以保存上一次访问的界面风格。</p><h2 id="计算机网络" tabindex="-1">计算机网络 <a class="header-anchor" href="#计算机网络" aria-label="Permalink to &quot;计算机网络&quot;">​</a></h2><h3 id="cdn-回源" tabindex="-1">CDN，回源 <a class="header-anchor" href="#cdn-回源" aria-label="Permalink to &quot;CDN，回源&quot;">​</a></h3><p>CDN 是内容分发⽹络，源站提供内容，CDN 节点进⾏内容分发，用户可以就近获取所需内容，降低⽹络拥塞，提⾼用户访问响应速度和命中率。</p><p>回源，当有用户访问某㇐个 URL 的时候，如果被解析到的那个 CDN 节点没有缓存响应的内容，或者是缓存已经到期，就会回源站去获取。如果没有⼈访问，那么 CDN 节点不会主动去源站拿的。</p><p>回源的策略间接决定了缓存的命中率，频繁回源会对源站产生较⼤的负担。</p>`,294),n=[r];function s(p,h,d,c,u,P){return a(),e("div",null,n)}const k=t(i,[["render",s]]);export{b as __pageData,k as default};
